class Solution {
    public int minStartingIndex(String s, String pattern) {
        int n = s.length();
        int m = pattern.length();
        int diff = 0;
        for (int i = 0; i < m; i++) {
            if (s.charAt(i) != pattern.charAt(i)) {
                diff++;
            }
        }
        if (diff > 1) {
            return -1;
        }
        int ans = -1;
        for (int i = 0; i <= n - m; i++) {
            int curDiff = 0;
            for (int j = 0; j < m; j++) {
                if (s.charAt(i + j) != pattern.charAt(j)) {
                    curDiff++;
                }
            }
            if (curDiff <= 1) {
                ans = Math.min(ans == -1 ? i : ans, i);
            }
        }
        return ans;
    }
}
